checker_dsl:
EXISTS (`constructor call CC`) {
  AND {
    (`CC constructs type with qualified name "java.text.SimpleDateFormat"`),
    EXISTS (`string literal SL`) {
      AND {
        (`SL is the argument at index 0 of CC`),
        EXISTS (`string value SV`) {
          AND {
            (`SV is the value of SL`),
            (`SV contains substring "%Y"`),
            (`SV contains substring "%M"`)
          }
        }
      }
    }
  }
}
